// ---- Back Stack Management ----

// ---- Define routes ----
sealed class Screen(val route: String) {
    object Home : Screen("home")
    object A : Screen("a")
    object B : Screen("b")
    object C : Screen("c")
    object D : Screen("d")
    object Login : Screen("login")
}

// ---- NavHost with back stack management ----
@Composable
fun BackStackNavigation() {
    val navController = rememberNavController()

    NavHost(
        navController = navController,
        startDestination = Screen.Home.route
    ) {
        composable(Screen.Home.route) {
            HomeScreen(
                onNavigateToA = { navController.navigate(Screen.A.route) },
                onNavigateToB = { navController.navigate(Screen.B.route) },
                onNavigateToLogin = {
                    navController.navigate(Screen.Login.route) {
                        popUpTo(Screen.Home.route) { inclusive = true }
                    }
                }
            )
        }

        composable(Screen.A.route) {
            AScreen(
                onNavigateToB = { navController.navigate(Screen.B.route) },
                onNavigateToC = { navController.navigate(Screen.C.route) },
                onBack = { navController.popBackStack() }
            )
        }

        composable(Screen.B.route) {
            BScreen(
                onNavigateToC = { navController.navigate(Screen.C.route) },
                onNavigateToD = { navController.navigate(Screen.D.route) },
                onBackToHome = {
                    navController.navigate(Screen.Home.route) {
                        popUpTo(Screen.Home.route) { inclusive = true }
                    }
                },
                onBack = { navController.popBackStack() }
            )
        }

        composable(Screen.C.route) {
            CScreen(
                onNavigateToD = { navController.navigate(Screen.D.route) },
                onBack = { navController.popBackStack() }
            )
        }

        composable(Screen.D.route) {
            DScreen(
                onBackToHome = {
                    navController.navigate(Screen.Home.route) {
                        popUpTo(Screen.Home.route) { inclusive = true }
                    }
                },
                onBack = { navController.popBackStack() }
            )
        }

        composable(Screen.Login.route) {
            LoginScreen(
                onLoginSuccess = {
                    navController.navigate(Screen.Home.route) {
                        popUpTo(Screen.Home.route) { inclusive = true }
                    }
                }
            )
        }
    }
}

