@Composable
fun BrokenBackStack() {
    val navController = rememberNavController()

    NavHost(navController, startDestination = "home") {
        // 1. Infinite back stack
        composable("home") {
            Button(onClick = { navController.navigate("a") }) {
                Text("Go to A")
            }
        }

        composable("a") {
            Button(onClick = { navController.navigate("b") }) {
                Text("Go to B")
            }
            Button(onClick = { navController.popBackStack() }) {
                Text("Back")  // Works but stack grows
            }
        }

        // 2. No popUpTo
        composable("b") {
            Button(onClick = {
                navController.navigate("home")  // Adds to stack
            }) {
                Text("Go to Home")
            }
        }

        // 3. Login without clearing stack
        composable("login") {
            Button(onClick = {
                navController.navigate("home")  // Home on top of login
            }) {
                Text("Login")
            }
        }

        // 4. Never clearing
        composable("profile") {
            Button(onClick = {
                navController.navigate("home")  // Stack grows
            }) {
                Text("Go to Home")
            }
        }
    }
}

phase2.explanation:
🤖 **Common back stack mistakes and fixes.**

| Mistake | Fix |
|---------|-----|
| No back navigation | Add back button |
| No popUpTo | Use popUpTo for navigation |
| Login without clearing | Clear stack on login |
| Infinite stack | Use popUpTo and inclusive |

**Fixes:**
```kotlin
// 1. Use popUpTo for home navigation
navController.navigate("home") {
    popUpTo("home") { inclusive = true }
}

// 2. Clear stack on login
navController.navigate("home") {
    popUpTo("home") { inclusive = true }
}

// 3. Use launchSingleTop
navController.navigate("home") {
    launchSingleTop = true
}

// 4. Back with popBackStack
Button(onClick = { navController.popBackStack() }) {
    Text("Back")
}
```

